site_id = #{siteId}, i18n_key = #{i18nKey}, i18n_desc = #{i18nDesc}, i18n_scope_cd = #{i18nScopeCd}, i18n_category = #{i18nCategory}, sort_ord = #{sortOrd}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
